"use client";
import { DemoLayout } from "../components/demo-layout";
import { Header } from "../components/header";

export default function page() {
	return (
		<>
			<Header />
			<DemoLayout />
		</>
	);
}

"use client";
import React from "react";
import { cn } from "@/lib/utils";
import { Logo } from "./logo";
import { useScroll } from "../hooks/use-scroll";
import { Button } from "@/registry/default/ui/button";
import { MobileNav } from "./mobile-nav";

export const navLinks = [
	{
		label: "Features",
		href: "#",
	},
	{
		label: "Pricing",
		href: "#",
	},
	{
		label: "About",
		href: "#",
	},
];

export function Header() {
	const headerRef = React.useRef<HTMLElement>(null);
	const scrolled = useScroll(10, undefined, headerRef);

	return (
		<header
			ref={headerRef}
			className={cn("sticky top-0 z-20 w-full border-transparent border-b", {
				"border-border bg-background/95 backdrop-blur-sm supports-backdrop-filter:bg-background/50":
					scrolled,
			})}
		>
			<nav className="mx-auto flex h-14 w-full max-w-5xl items-center justify-between px-4">
				<a
					className="rounded-md p-2 hover:bg-muted dark:hover:bg-muted/50"
					href="#"
				>
					<Logo className="h-8 w-auto" />
				</a>
				<div className="hidden items-center gap-2 md:flex">
					{navLinks.map((link) => (
						<Button asChild key={link.label} size="sm" variant="ghost">
							<a href={link.href}>{link.label}</a>
						</Button>
					))}
					<Button size="sm" variant="outline">
						Sign In
					</Button>
					<Button size="sm">Get Started</Button>
				</div>
				<MobileNav />
			</nav>
		</header>
	);
}

import { cn } from "@/lib/utils";
import React from "react";
import { Button } from "@/registry/default/ui/button";
import { Portal, PortalBackdrop } from "./ui/portal";
import { navLinks } from "./header";
import { XIcon, MenuIcon } from "lucide-react";

export function MobileNav() {
	const [open, setOpen] = React.useState(false);

	return (
		<div className="md:hidden">
			<Button
				aria-controls="mobile-menu"
				aria-expanded={open}
				aria-label="Toggle menu"
				className="md:hidden"
				onClick={() => setOpen(!open)}
				size="icon"
				variant="outline"
			>
				{open ? (
					<XIcon className="size-4.5" />
				) : (
					<MenuIcon className="size-4.5" />
				)}
			</Button>
			{open && (
				<Portal className="top-14" id="mobile-menu">
					<PortalBackdrop />
					<div
						className={cn(
							"data-[slot=open]:zoom-in-97 ease-out data-[slot=open]:animate-in",
							"size-full p-4"
						)}
						data-slot={open ? "open" : "closed"}
					>
						<div className="grid gap-y-2">
							{navLinks.map((link) => (
								<Button
									asChild
									className="justify-start"
									key={link.label}
									variant="ghost"
								>
									<a href={link.href}>{link.label}</a>
								</Button>
							))}
						</div>
						<div className="mt-12 flex flex-col gap-2">
							<Button className="w-full" variant="outline">
								Sign In
							</Button>
							<Button className="w-full">Get Started</Button>
						</div>
					</div>
				</Portal>
			)}
		</div>
	);
}

export function DemoLayout() {
	return (
		<main className="mx-auto w-full max-w-5xl px-4 py-10">
			<section className="grid gap-4">
				<div className="h-8 w-48 rounded-lg bg-muted" />
				<div className="h-4 w-full max-w-2xl rounded bg-muted" />
				<div className="h-4 w-full max-w-xl rounded bg-muted" />
			</section>
			<section className="mt-10 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
				{Array.from({ length: 9 }).map((_, index) => (
					<div
						className="rounded-xl border bg-card p-4 shadow-xs"
						key={index}
					>
						<div className="h-32 rounded-lg bg-muted" />
						<div className="mt-4 h-4 w-2/3 rounded bg-muted" />
						<div className="mt-3 h-3 w-full rounded bg-muted" />
						<div className="mt-2 h-3 w-4/5 rounded bg-muted" />
					</div>
				))}
			</section>
			<section className="mt-10 grid gap-4">
				{Array.from({ length: 8 }).map((_, index) => (
					<div className="rounded-xl border bg-card p-5" key={index}>
						<div className="h-4 w-40 rounded bg-muted" />
						<div className="mt-4 h-3 w-full rounded bg-muted" />
						<div className="mt-2 h-3 w-11/12 rounded bg-muted" />
					</div>
				))}
			</section>
		</main>
	);
}

import { cn } from "@/lib/utils";

function Portal({ className, ...props }: React.ComponentProps<"div">) {
	return (
		<div
			className={cn(
				"absolute inset-x-0 z-40 flex h-[calc(100dvh-3.5rem)] max-h-[calc(100dvh-3.5rem)] flex-col overflow-hidden",
				className
			)}
			{...props}
		/>
	);
}

function PortalBackdrop({ className, ...props }: React.ComponentProps<"div">) {
	return (
		<div
			className={cn(
				"data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 absolute inset-0 -z-1 bg-background/95 backdrop-blur-sm duration-500 data-[state=closed]:animate-out data-[state=open]:animate-in supports-backdrop-filter:bg-background/60",
				className
			)}
			{...props}
		/>
	);
}

export { Portal, PortalBackdrop };

"use client";
import { useEffect, useState, type RefObject } from "react";

export function useScroll(
	downThreshold: number,
	upThreshold?: number,
	targetRef?: RefObject<HTMLElement | null>
) {
	const [scrolled, setScrolled] = useState(false);
	const scrollUpThreshold = upThreshold ?? downThreshold / 2;

	useEffect(() => {
		const scrollContainer = getScrollContainer(targetRef?.current);

		const handleScroll = () => {
			const y =
				scrollContainer instanceof Window
					? window.scrollY
					: scrollContainer.scrollTop;
			// Hysteresis: different thresholds for up/down to prevent flickering
			setScrolled((prev) => {
				if (prev) {
					// Currently scrolled - only unscroll when below lower threshold
					return y > scrollUpThreshold;
				}
				// Currently not scrolled - only scroll when above higher threshold
				return y > downThreshold;
			});
		};

		scrollContainer.addEventListener("scroll", handleScroll, { passive: true });
		handleScroll();
		return () => scrollContainer.removeEventListener("scroll", handleScroll);
	}, [downThreshold, scrollUpThreshold, targetRef]);

	return scrolled;
}

function getScrollContainer(element?: HTMLElement | null) {
	let parent = element?.parentElement ?? null;

	while (parent) {
		const { overflowY } = window.getComputedStyle(parent);
		const canScroll = parent.scrollHeight > parent.clientHeight;

		if (canScroll && (overflowY === "auto" || overflowY === "scroll")) {
			return parent;
		}

		parent = parent.parentElement;
	}

	return window;
}
